using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== ALL ERRORS ===");
build.VisitAllChildren<Error>(error => {
    Console.WriteLine($"[{error.ProjectFile}]");
    Console.WriteLine($"  {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
    Console.WriteLine();
});

Console.WriteLine("=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(warning => {
    Console.WriteLine($"[{warning.ProjectFile}]");
    Console.WriteLine($"  {warning.File}({warning.LineNumber},{warning.ColumnNumber}): warning {warning.Code}: {warning.Text}");
    Console.WriteLine();
});

Console.WriteLine("=== PROJECT SUMMARY ===");
build.VisitAllChildren<Project>(project => {
    Console.WriteLine($"Project: {project.Name} - Succeeded: {project.Succeeded}");
});
