using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get all source files referenced during Csc task
Console.WriteLine("=== CSC TASK ITEMS (Sources) ===");
build.VisitAllChildren<Task>(task => {
    if (task.Name == "Csc") {
        var parent = task.Parent;
        Console.WriteLine($"\n--- Csc in project context ---");
        task.VisitAllChildren<Item>(item => {
            Console.WriteLine($"  Item: {item.Name} = {item.Text}");
        });
        task.VisitAllChildren<Parameter>(param => {
            if (param.Name == "Sources" || param.Name == "References") {
                Console.WriteLine($"  Param: {param.Name}");
                foreach (var child in param.Children) {
                    Console.WriteLine($"    {child}");
                }
            }
        });
    }
});

// Get project file contents from Items
Console.WriteLine("\n=== LOOKING FOR CSPROJ CONTENT ===");
build.VisitAllChildren<Import>(imp => {
    Console.WriteLine($"  Import: {imp.Name} -> {imp.ProjectFilePath}");
});
CSHARP

