using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get all source files and references used by Csc tasks
Console.WriteLine("=== CSC TASK DETAILS ===");
build.VisitAllChildren<Task>(task => {
    if (task.Name == "Csc") {
        Console.WriteLine($"\n--- Csc Task ---");
        task.VisitAllChildren<Parameter>(param => {
            if (param.Name == "Sources" || param.Name == "References") {
                Console.WriteLine($"  Param: {param.Name}");
                foreach (var child in param.Children) {
                    Console.WriteLine($"    {child}");
                }
            }
        });
    }
});

// Show all items in projects 
Console.WriteLine("\n=== PROJECT ITEMS (PackageReference) ===");
build.VisitAllChildren<AddItem>(addItem => {
    if (addItem.Name == "PackageReference") {
        Console.WriteLine($"  {addItem.Name}: {string.Join(", ", addItem.Children.Select(c => c.ToString()))}");
    }
});

// Show project references
Console.WriteLine("\n=== PROJECT REFERENCES ===");
build.VisitAllChildren<AddItem>(addItem => {
    if (addItem.Name == "ProjectReference") {
        Console.WriteLine($"  {addItem.Name}: {string.Join(", ", addItem.Children.Select(c => c.ToString()))}");
    }
});

// Get csproj content via SourceFilesProjectOutputGroupOutput or similar
Console.WriteLine("\n=== ALL CSPROJ AND CS FILES (from items) ===");
build.VisitAllChildren<AddItem>(addItem => {
    if (addItem.Name == "Compile") {
        Console.WriteLine($"  Compile: {string.Join(", ", addItem.Children.Select(c => c.ToString()))}");
    }
});
