using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program {
    static void Main(string[] args) {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        // Print all errors with full context
        Console.WriteLine("=== ERRORS ===");
        build.VisitAllChildren<Error>(error => {
            Console.WriteLine($"Project: {error.ProjectFile}");
            Console.WriteLine($"File: {error.File}");
            Console.WriteLine($"Line: {error.LineNumber}, Col: {error.ColumnNumber}");
            Console.WriteLine($"Code: {error.Code}");
            Console.WriteLine($"Message: {error.Text}");
            Console.WriteLine();
        });

        // Get embedded file contents from the binlog (SourceFileInfo nodes or similar)
        Console.WriteLine("=== SEARCHING FOR CSPROJ CONTENT ===");

        // Try to find csproj content via properties
        build.VisitAllChildren<Project>(project => {
            if (project.ProjectFile != null && project.ProjectFile.EndsWith(".csproj")) {
                Console.WriteLine($"\n--- Project: {project.ProjectFile} ---");
                // Look for NuGet-related items
                project.VisitAllChildren<AddItem>(item => {
                    if (item.Name == "PackageReference" || item.Name == "ProjectReference" || item.Name == "Reference") {
                        Console.WriteLine($"  {item.Name}: {string.Join(", ", item.Children.Select(c => c.ToString()))}");
                    }
                });
            }
        });

        // Try to get source file content from SourceFile nodes
        Console.WriteLine("\n=== SOURCE FILES ===");
        build.VisitAllChildren<SourceFile>(sf => {
            Console.WriteLine($"  SourceFile: {sf.SourceFilePath}");
        });
    }
}
