using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program {
    static void Main(string[] args) {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        // Try to find source content via SourceFilesProjectOutputGroupOutput
        Console.WriteLine("=== ALL NODE TYPES ===");
        var types = new HashSet<string>();
        build.VisitAllChildren<BaseNode>(node => {
            types.Add(node.GetType().Name);
        });
        foreach (var t in types.OrderBy(t => t)) {
            Console.WriteLine($"  {t}");
        }

        // Look for text/message nodes that might contain source content
        Console.WriteLine("\n=== MESSAGES CONTAINING .cs ===");
        build.VisitAllChildren<Message>(msg => {
            if (msg.Text != null && (msg.Text.Contains("UserService.cs") || msg.Text.Contains("Models.cs") || msg.Text.Contains("Program.cs")) 
                && !msg.Text.Contains("obj/") && !msg.Text.Contains("\\obj\\")) {
                Console.WriteLine($"  [{msg.Importance}] {msg.Text.Substring(0, Math.Min(msg.Text.Length, 200))}");
            }
        });

        // Look for the Csc command line to get actual source paths
        Console.WriteLine("\n=== CSC COMMAND LINES ===");
        build.VisitAllChildren<Task>(task => {
            if (task.Name == "Csc") {
                task.VisitAllChildren<Parameter>(param => {
                    if (param.Name == "CommandLineArguments") {
                        Console.WriteLine($"  CmdLine: {param.Children.FirstOrDefault()?.ToString()?.Substring(0, Math.Min(200, param.Children.FirstOrDefault()?.ToString()?.Length ?? 0))}");
                    }
                });
                // also check the message children for command line
                task.VisitAllChildren<Message>(msg => {
                    if (msg.Text != null && msg.Text.Contains("csc")) {
                        Console.WriteLine($"  Msg: {msg.Text.Substring(0, Math.Min(msg.Text.Length, 300))}");
                    }
                });
            }
        });

        // Get the NuGet assets to check packages  
        Console.WriteLine("\n=== NUGET: project.assets.json CHECK ===");
        build.VisitAllChildren<SourceFile>(sf => {
            Console.WriteLine($"  SourceFile path: {sf.SourceFilePath}");
        });
    }
}
